suspend fun loadRequired(): Pair<User, Settings> = coroutineScope {
    val user = async { userApi.getUser() }
    val settings = async { settingsApi.getSettings() }
    user.await() to settings.await()
}

suspend fun loadDashboard(): Dashboard = supervisorScope {
    val profile = async { profileApi.get() }
    val badges = async { runCatchingCancellable { badgeApi.get() } }
    val suggestions = async { runCatchingCancellable { suggestionApi.get() } }

    Dashboard(
        profile = profile.await(),
        badges = badges.await().getOrDefault(emptyList()),
        suggestions = suggestions.await().getOrDefault(emptyList())
    )
}

suspend inline fun <T> runCatchingCancellable(crossinline block: suspend () -> T): Result<T> = try {
    Result.success(block())
} catch (e: CancellationException) {
    throw e
} catch (e: Throwable) {
    Result.failure(e)
}
